        m.Text.Contains("sign", StringComparison.OrdinalIgnoreCase))) {
        Console.WriteLine($"[MSG] {m.Text}");
    }
});

// Search for Exec tasks that invoke signtool
Console.WriteLine("\n=== EXEC TASKS ===");
build.VisitAllChildren<Microsoft.Build.Logging.StructuredLogger.Task>(t => {
    if (t.Name == "Exec" || t.Name == "SignFile") {
        PrintNode(t, 0);
    }
});

void PrintNode(BaseNode node, int indent) {
    var prefix = new string(' ', indent * 2);
    if (node is TreeNode treeNode) {
        foreach (var child in treeNode.Children) {
            if (child is BaseNode bn) {
                Console.WriteLine($"{prefix}{bn.GetType().Name}: {bn}");
                PrintNode(bn, indent + 1);
            }
        }
    }
}
